#include <bits/stdc++.h>
using namespace std;
#define int long long
const int N = 18;
const int S = 1 << 18;
int dp[S][N];
vector<pair<int,int>>g[N];
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int n,m;
	cin>>n>>m;
	for(int i=0; i<m; i++) {
		int u,v,w;
		cin>>u>>v>>w;
		g[u].push_back({v,w});
	}
	memset(dp,-1,sizeof(dp));
	dp[1][0]=0;
	for(int i=1; i<(1<<n); i++) {
		for(int u=0; u<n; u++) {
			if(dp[i][u]==-1||!((i>>u)&1))continue;
			for(auto &ed:g[u]) {
				int v=ed.first,w=ed.second;
				if(!((i>>v)&1)) {
					int aa=i|(1<<v);
					dp[aa][v]=max(dp[aa][v],dp[i][u]+w);
				}
			}
		}
	}
	int ans=0;
	for(int i=0; i<(1<<n); i++) {
		if((i>>(n-1))&1) {
			ans=max(ans,dp[i][n-1]);
		}
	}
	cout<<ans;
	return 0;
}
